SELECT t, groupArray((cat, value)) AS groupArr FROM ( SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, cat, sum(v) value FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706) AND (a, b) IN (SELECT a, b FROM default.other LIMIT 10) GROUP BY t, cat ORDER BY t, cat) GROUP BY t ORDER BY t